        let cycle = i, steps = edges.length;
        while (parent[cycle] !== 0 && steps-- > 0) {
            cycle = parent[cycle];
        }
        if (steps === -1) {
            if (candidateA === null) return [parent[i], i];
            else return candidateA;
        }
    }

    return candidateB;
}
